import{_ as s,G as t,c as l,o as n,j as e,J as d,a6 as o,a as r}from"./chunks/framework.D3uGTwuV.js";const _=JSON.parse('{"title":"解除特定端口占用","description":"","frontmatter":{},"headers":[],"relativePath":"技巧/解除特定端口占用.md","filePath":"技巧/解除特定端口占用.md","lastUpdated":1775109753000}'),p={name:"技巧/解除特定端口占用.md"};function c(h,a,k,g,b,u){const i=t("ArticleMetadata");return n(),l("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1775109753000"},[a[0]||(a[0]=e("h1",{id:"解除特定端口占用",tabindex:"-1"},[r("解除特定端口占用 "),e("a",{class:"header-anchor",href:"#解除特定端口占用","aria-label":"Permalink to “解除特定端口占用”"},"​")],-1)),d(i),a[1]||(a[1]=o('<p>在 Windows 系统中，你可以使用命令行来查找和终止占用特定端口的进程，也可以使用一段指令清除所有占用的端口。下面是具体的方法：</p><h2 id="_1-查找占用端口的进程" tabindex="-1">1. 查找占用端口的进程 <a class="header-anchor" href="#_1-查找占用端口的进程" aria-label="Permalink to “1. 查找占用端口的进程”">​</a></h2><p>使用 <code>netstat</code> 命令查找哪个进程占用了特定端口。例如，查找占用 8080 端口的进程：</p><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>netstat -ano | findstr :8080</span></span></code></pre></div><p>输出示例：</p><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>TCP    0.0.0.0:8080           0.0.0.0:0              LISTENING       1234</span></span></code></pre></div><p>其中 <code>1234</code> 是进程 ID (PID)。</p><h2 id="_2-终止占用端口的进程" tabindex="-1">2. 终止占用端口的进程 <a class="header-anchor" href="#_2-终止占用端口的进程" aria-label="Permalink to “2. 终止占用端口的进程”">​</a></h2><p>使用 <code>taskkill</code> 命令终止该进程：</p><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>taskkill /PID 1234 /F</span></span></code></pre></div><p>参数说明：</p><ul><li><code>/PID</code> 指定要终止的进程 ID</li><li><code>/F</code> 强制终止进程</li></ul><h2 id="一段指令清除所有占用端口的进程" tabindex="-1">一段指令清除所有占用端口的进程 <a class="header-anchor" href="#一段指令清除所有占用端口的进程" aria-label="Permalink to “一段指令清除所有占用端口的进程”">​</a></h2><p>如果你想一次性终止所有 LISTENING 状态的端口占用进程，可以使用以下命令：</p><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>for /f &quot;tokens=5&quot; %a in (&#39;netstat -ano ^| findstr LISTENING&#39;) do taskkill /PID %a /F</span></span></code></pre></div><p>这个命令的解释：</p><ul><li><code>netstat -ano</code> 列出所有网络连接和监听端口</li><li><code>findstr LISTENING</code> 过滤出处于监听状态的端口</li><li><code>for /f &quot;tokens=5&quot;</code> 循环处理输出的第5列（PID）</li><li><code>taskkill /PID %a /F</code> 终止每个找到的进程</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ul><li>请谨慎使用批量终止命令，因为它可能会终止一些系统关键进程</li><li>某些系统进程可能需要管理员权限才能终止，如果遇到权限问题，请以管理员身份运行命令提示符(cmd)</li><li>建议先使用 <code>netstat -ano</code> 查看所有连接，确认要终止的进程后再执行终止操作</li></ul><p>这些方法可以帮助你管理和清除端口占用问题。</p>',20))])}const m=s(p,[["render",c]]);export{_ as __pageData,m as default};
